def convert_to_standard_date(date_string: str) -> str:
    """
    Convert any common date string format to standard YYYY-MM-DD format.

    Args:
        date_string: A date string in various formats

    Returns:
        A date string in YYYY-MM-DD format

    Raises:
        ValueError: If the date string cannot be parsed
    """
    # List of common date formats to try
    date_formats = [
        "%Y-%m-%d",  # 2024-03-15
        "%Y/%m/%d",  # 2024/03/15
        "%d-%m-%Y",  # 15-03-2024
        "%d/%m/%Y",  # 15/03/2024
        "%m-%d-%Y",  # 03-15-2024
        "%m/%d/%Y",  # 03/15/2024
        "%Y%m%d",  # 20240315
        "%d.%m.%Y",  # 15.03.2024
        "%Y.%m.%d",  # 2024.03.15
        "%B %d, %Y",  # March 15, 2024
        "%b %d, %Y",  # Mar 15, 2024
        "%d %B %Y",  # 15 March 2024
        "%d %b %Y",  # 15 Mar 2024
        "%Y-%m-%d %H:%M:%S",  # 2024-03-15 14:30:00
        "%Y/%m/%d %H:%M:%S",  # 2024/03/15 14:30:00
        "%d-%m-%Y %H:%M:%S",  # 15-03-2024 14:30:00
        "%m-%d-%Y %H:%M:%S",  # 03-15-2024 14:30:00
        "%Y-%m-%dT%H:%M:%S",  # 2024-03-15T14:30:00 (ISO format)
        "%Y-%m-%dT%H:%M:%SZ",  # 2024-03-15T14:30:00Z (ISO with Z)
        "%a, %d %b %Y %H:%M:%S",  # Mon, 15 Mar 2024 14:30:00
        "%A, %B %d, %Y",  # Monday, March 15, 2024
    ]

    # Remove extra whitespace
    date_string = date_string.strip()

    # Try each format
    for fmt in date_formats:
        try:
            date_obj = datetime.datetime.strptime(date_string, fmt)
            return date_obj.strftime("%Y-%m-%d")
        except ValueError:
            continue

    # If no format matched, raise an error
    raise ValueError(f"Unable to parse date string: '{date_string}'. "
                     f"Please provide a valid date format.")

def generate_hash_id(*args):
    hash_input = "|".join(str(a) for a in args)
    return hashlib.md5(hash_input.encode('utf-8')).hexdigest()

